import { useEffect, useState } from "react";
import axios from "axios";

function Results() {
  const [results, setResults] = useState([]);

  useEffect(() => {
    axios.get("http://localhost:5000/results")
      .then(res => setResults(res.data));
  }, []);

  return (
    <div>
      <h2>История игр</h2>

      {results.map((r) => (
        <div key={r.id}>
          {r.name}: {r.score}
        </div>
      ))}
    </div>
  );
}

export default Results;
